public boolean stoneGameIX(int[] stones) {
    int[] cnt = new int[3];
    for (int s : stones) {
        cnt[s % 3]++;
    }
    return (cnt[1] != 0 && cnt[2] != 0) || (cnt[1] > cnt[2] ? cnt[1] > cnt[2] + 2 : cnt[2] > cnt[1] + 1);
}
